(function() {
    // ১. পুরনো UI সরানো
    const existing = document.getElementById('ultra-scroll-ui');
    if (existing) existing.remove();

    // ২. স্পেশাল স্ক্রল ফাংশন
    function universalPush(direction) {
        const isUp = direction === 'up';
        const url = window.location.href;

        // --- ক. ইউটিউব শর্টস এর জন্য বিশেষ 'কীবোর্ড হ্যাক' ---
        if (url.includes("youtube.com/shorts")) {
            console.log("ইউটিউব শর্টস ডিটেক্টেড! কীবোর্ড ইভেন্ট পাঠাচ্ছি...");
            const keyCode = isUp ? 38 : 40; // ৩৮ = Up, ৪০ = Down

            const eventObj = {
                bubbles: true,
                cancelable: true,
                keyCode: keyCode,
                which: keyCode,
                view: window
            };

            // ইউটিউবের মেইন বডি বা একটিভ এলিমেন্টে কিবোর্ড প্রেস পাঠানো
            const target = document.activeElement || document.body;
            target.dispatchEvent(new KeyboardEvent('keydown', eventObj));
            target.dispatchEvent(new KeyboardEvent('keyup', eventObj));
            return; // শর্টসের কাজ শেষ
        }

        // --- খ. জেমিনি বা অন্যান্য সাইটের জন্য আপনার সফল লজিক ---
        const offset = isUp ? -window.innerHeight * 0.7 : window.innerHeight * 0.7;
        let target = document.elementFromPoint(window.innerWidth / 2, window.innerHeight / 2);

        while (target) {
            const style = window.getComputedStyle(target);
            if ((style.overflowY === 'auto' || style.overflowY === 'scroll') && target.scrollHeight > target.clientHeight) {
                target.scrollBy({ top: offset, behavior: 'smooth' });
                return;
            }
            target = target.parentElement;
        }

        // --- গ. ব্যাকআপ (সাধারণ পেজ) ---
        window.scrollBy({ top: offset, behavior: 'smooth' });
    }

    // ৩. ↑ এবং ↓ বাটন তৈরি
    const ui = document.createElement('div');
    ui.id = 'ultra-scroll-ui';
    ui.style.cssText = 'position:fixed; bottom:100px; right:20px; z-index:9999999; display:flex; flex-direction:column; gap:15px; pointer-events:none;';

    function createBtn(text, dir, color) {
        const btn = document.createElement('div');
        btn.innerText = text;
        btn.style.cssText = `width:65px; height:65px; background:${color}; color:white; border-radius:50%; display:flex; align-items:center; justify-content:center; font-size:35px; font-weight:bold; box-shadow:0 8px 25px rgba(0,0,0,0.5); cursor:pointer; pointer-events:auto; user-select:none; -webkit-tap-highlight-color:transparent;`;
        btn.onclick = () => universalPush(dir);
        return btn;
    }

    ui.appendChild(createBtn('↑', 'up', '#4285F4')); 
    ui.appendChild(createBtn('↓', 'down', '#EA4335')); 
    document.body.appendChild(ui);

    console.log("শর্টস ক্রাশার রেডি! 🚀");
})();
